transform_js:
const numRows = rawData.rows.length;
const grids = [];
const xAxes = [];
const yAxes = [];
const series = [];

const rowHeight = 90 / numRows;

rawData.rows.forEach((r, i) => {
  const top = (i * rowHeight + 10) + '%';
  const height = (rowHeight - 10) + '%';

  grids.push({
    top: top,
    height: height,
    left: '25%',
    right: '5%'
  });

  xAxes.push({
    gridIndex: i,
    type: 'value',
    max: r.good,
    splitLine: { show: false },
    axisTick: { show: true },
    axisLine: { show: true },
    axisLabel: { formatter: r.title.includes('%') ? '{value}%' : '{value}' }
  });

  yAxes.push({
    gridIndex: i,
    type: 'category',
    data: [r.title],
    axisTick: { show: false },
    axisLine: { show: false },
    axisLabel: { 
      margin: 15,
      align: 'right',
      formatter: function(value) {
         const parts = value.split('\\n');
         return '{title|' + parts[0] + '}\n{subtitle|' + (parts[1]||'') + '}';
      },
      rich: {
        title: { fontWeight: 'bold', fontSize: 13, color: '#333', lineHeight: 18 },
        subtitle: { fontSize: 11, color: '#777' }
      }
    }
  });

  // Background Series 1 (Poor)
  series.push({
    name: 'Poor',
    type: 'bar',
    xAxisIndex: i,
    yAxisIndex: i,
    stack: 'bg_' + i,
    barWidth: '60%',
    itemStyle: { color: r.colors[0] },
    data: [r.poor],
    animation: false,
    silent: true
  });

  // Background Series 2 (Satisfactory)
  series.push({
    name: 'Satisfactory',
    type: 'bar',
    xAxisIndex: i,
    yAxisIndex: i,
    stack: 'bg_' + i,
    barWidth: '60%',
    itemStyle: { color: r.colors[1] },
    data: [r.satisfactory - r.poor],
    animation: false,
    silent: true
  });

  // Background Series 3 (Good)
  series.push({
    name: 'Good',
    type: 'bar',
    xAxisIndex: i,
    yAxisIndex: i,
    stack: 'bg_' + i,
    barWidth: '60%',
    itemStyle: { color: r.colors[2] },
    data: [r.good - r.satisfactory],
    animation: false,
    silent: true
  });

  // Measure Series
  series.push({
    name: 'Measure',
    type: 'bar',
    xAxisIndex: i,
    yAxisIndex: i,
    barGap: '-75%',
    barWidth: '30%',
    z: 3,
    itemStyle: { color: r.colors[3] },
    data: [{ value: r.measure, itemStyle: { borderRadius: [0, 2, 2, 0] } }]
  });

  // Target Series
  series.push({
    name: 'Target',
    type: 'scatter',
    xAxisIndex: i,
    yAxisIndex: i,
    symbol: 'rect',
    symbolSize: [4, 30],
    z: 4,
    itemStyle: { color: r.colors[4] },
    data: [r.target]
  });
});

transformedData = { grids, xAxes, yAxes, series };

echarts_js:
option = {
  title: {
    text: 'Cloud Infrastructure Health (Bullet Chart)',
    left: 'center',
    textStyle: { fontSize: 18, fontWeight: 'bold' }
  },
  tooltip: {
     trigger: 'item',
     formatter: '{a}: {c}'
  },
  grid: transformedData.grids,
  xAxis: transformedData.xAxes,
  yAxis: transformedData.yAxes,
  series: transformedData.series
};
